// Kernel definition
__global__ void vectorAdd(float* A, float* B, float* C, int n) {
 // Calculate global thread ID
 int idx = blockIdx.x * blockDim.x + threadIdx.x;

 // Boundary check
 if (idx < n) {
 C[idx] = A[idx] + B[idx];
 }
}

// Host code to launch kernel
int main() {
 int n = 1024 * 1024; // 1M elements
 size_t bytes = n * sizeof(float);

 // Allocate and initialize host arrays
 float *h_A = (float*)malloc(bytes);
 float *h_B = (float*)malloc(bytes);
 float *h_C = (float*)malloc(bytes);

 // Allocate device memory
 float *d_A, *d_B, *d_C;
 cudaMalloc(&d_A, bytes);
 cudaMalloc(&d_B, bytes);
 cudaMalloc(&d_C, bytes);

 // Copy input data to device
 cudaMemcpy(d_A, h_A, bytes, cudaMemcpyHostToDevice);
 cudaMemcpy(d_B, h_B, bytes, cudaMemcpyHostToDevice);

 // Launch kernel: 256 threads per block
 int blockSize = 256;
 int gridSize = (n + blockSize - 1) / blockSize;
 vectorAdd<<<gridSize, blockSize>>>(d_A, d_B, d_C, n);

 // Copy result back to host
 cudaMemcpy(h_C, d_C, bytes, cudaMemcpyDeviceToHost);

 // Free memory
 cudaFree(d_A); cudaFree(d_B); cudaFree(d_C);
 free(h_A); free(h_B); free(h_C);

 return 0;
}

#define TILE_WIDTH 16

__global__ void matrixMulShared(float* A, float* B, float* C, int M, int N, int K) {
 // Shared memory for tiles
 __shared__ float sharedA[TILE_WIDTH][TILE_WIDTH];
 __shared__ float sharedB[TILE_WIDTH][TILE_WIDTH];

 // Thread indices
 int bx = blockIdx.x; int by = blockIdx.y;
 int tx = threadIdx.x; int ty = threadIdx.y;

 // Global row and column for this thread
 int row = by * TILE_WIDTH + ty;
 int col = bx * TILE_WIDTH + tx;

 float sum = 0.0f;

 // Loop over tiles
 for (int m = 0; m < (K + TILE_WIDTH - 1) / TILE_WIDTH; m++) {
 // Load tiles into shared memory (coalesced access)
 if (row < M && m * TILE_WIDTH + tx < K)
 sharedA[ty][tx] = A[row * K + m * TILE_WIDTH + tx];
 else
 sharedA[ty][tx] = 0.0f;

 if (col < N && m * TILE_WIDTH + ty < K)
 sharedB[ty][tx] = B[(m * TILE_WIDTH + ty) * N + col];
 else
 sharedB[ty][tx] = 0.0f;

 // Synchronize to ensure tiles are loaded
 __syncthreads();

 // Compute partial result for this tile
 for (int k = 0; k < TILE_WIDTH; k++)
 sum += sharedA[ty][k] * sharedB[k][tx];

 // Synchronize before loading next tile
 __syncthreads();
 }

 // Write result
 if (row < M && col < N)
 C[row * N + col] = sum;
}

// Parallel reduction - version with bank conflict awareness
__global__ void reduce(float* input, float* output, int n) {
 // Shared memory for reduction
 __shared__ float sdata[256];

 // Load input into shared memory
 unsigned int tid = threadIdx.x;
 unsigned int idx = blockIdx.x * blockDim.x + threadIdx.x;

 sdata[tid] = (idx < n) ? input[idx] : 0.0f;
 __syncthreads();

 // Perform reduction in shared memory
 for (unsigned int s = blockDim.x / 2; s > 32; s >>= 1) {
 if (tid < s) {
 sdata[tid] += sdata[tid + s];
 }
 __syncthreads();
 }

 // Warp-level reduction (no sync needed within warp)
 if (tid < 32) {
 volatile float* smem = sdata;
 if (blockDim.x >= 64) smem[tid] += smem[tid + 32];
 smem[tid] += smem[tid + 16];
 smem[tid] += smem[tid + 8];
 smem[tid] += smem[tid + 4];
 smem[tid] += smem[tid + 2];
 smem[tid] += smem[tid + 1];
 }

 // Write result for this block
 if (tid == 0) {
 output[blockIdx.x] = sdata[0];
 }
}
